import { buildBitfabRequestHeaders } from "../clientHeaders.js";
import { getConfig } from "../config.js";
/**
 * Notify the Bitfab server that a skill was invoked so it can emit a
 * server-side `api:plugin_skill_invoke` analytics event. Silently no-ops when the
 * user is not authenticated and never throws — telemetry must never block
 * skill execution.
 */
export async function runTrackSkill(skillName, pluginVersion, platform) {
    const config = getConfig();
    if (!config.apiKey) {
        return;
    }
    const headers = buildBitfabRequestHeaders(config.apiKey, pluginVersion, platform);
    try {
        const response = await fetch(`${config.serviceUrl}/api/plugin/analytics/skill`, {
            method: "POST",
            headers,
            body: JSON.stringify({ skillName }),
        });
        if (config.debug && !response.ok) {
            console.error(`trackSkill: server returned ${response.status} for skill "${skillName}"`);
        }
    }
    catch (err) {
        if (config.debug) {
            const message = err instanceof Error ? err.message : String(err);
            console.error(`trackSkill: request failed for "${skillName}": ${message}`);
        }
    }
}
